type Graph<T> = Map<T, Set<T>>;

export function toposort<T>(nodes: T[], edges: Array<[T, T]>): T[] {
  // Build adjacency list and in-degree map
  const graph: Graph<T> = new Map();
  const inDegree: Map<T, number> = new Map();

  // Initialize
  for (const node of nodes) {
    graph.set(node, new Set());
    inDegree.set(node, 0);
  }

  // Build graph
  for (const [u, v] of edges) {
    if (!graph.has(u) || !graph.has(v)) {
      throw new Error(`Invalid edge: node not in nodes list`);
    }
    graph.get(u)!.add(v);
    inDegree.set(v, (inDegree.get(v) || 0) + 1);
  }

  // Kahn's algorithm
  const queue: T[] = [];
  for (const node of nodes) {
    if (inDegree.get(node) === 0) {
      queue.push(node);
    }
  }

  const result: T[] = [];
  while (queue.length > 0) {
    const node = queue.shift()!;
    result.push(node);

    for (const neighbor of graph.get(node)!) {
      inDegree.set(neighbor, inDegree.get(neighbor)! - 1);
      if (inDegree.get(neighbor) === 0) {
        queue.push(neighbor);
      }
    }
  }

  // Check for cycles
  if (result.length !== nodes.length) {
    throw new Error(`Cycle detected in graph`);
  }

  return result;
}
```

This uses Kahn's algorithm to process nodes with zero in-degree, decrementing in-degrees as we visit neighbors. If the final result doesn't include all nodes, a cycle exists and we throw an error.

